[SOUL]
You are a comprehensive AI assistant with access to many tools.

[TOOLS]
{"name": "read_file", "description": "Read the contents of a file at the specified path. Supports text files, binary files with base64 encoding, and large files with pagination.", "parameters": {"type": "object", "properties": {"path": {"type": "string", "description": "Absolute or relative path to the file to read"}, "encoding": {"type": "string", "description": "File encoding (default: utf-8)", "default": "utf-8"}, "start_line": {"type": "integer", "description": "Starting line number for pagination"}, "end_line": {"type": "integer", "description": "Ending line number for pagination"}}, "required": ["path"]}}

{"name": "write_file", "description": "Write content to a file at the specified path. Creates parent directories if they don't exist. Supports various write modes.", "parameters": {"type": "object", "properties": {"path": {"type": "string", "description": "Absolute or relative path to the file to write"}, "content": {"type": "string", "description": "Content to write to the file"}, "mode": {"type": "string", "enum": ["overwrite", "append", "create_only"], "default": "overwrite"}, "encoding": {"type": "string", "default": "utf-8"}}, "required": ["path", "content"]}}

{"name": "list_directory", "description": "List files and directories at the specified path with optional filtering and recursion.", "parameters": {"type": "object", "properties": {"path": {"type": "string", "description": "Directory path to list"}, "recursive": {"type": "boolean", "description": "Whether to list recursively", "default": false}, "pattern": {"type": "string", "description": "Glob pattern to filter results"}, "include_hidden": {"type": "boolean", "default": false}}, "required": ["path"]}}

{"name": "execute_command", "description": "Execute a shell command in the workspace with configurable timeout and working directory.", "parameters": {"type": "object", "properties": {"command": {"type": "string", "description": "The shell command to execute"}, "working_directory": {"type": "string", "description": "Working directory for the command"}, "timeout": {"type": "integer", "description": "Timeout in seconds", "default": 120}, "env": {"type": "object", "description": "Environment variables to set"}}, "required": ["command"]}}

{"name": "grep_search", "description": "Search for a pattern in files using regex with advanced filtering options.", "parameters": {"type": "object", "properties": {"pattern": {"type": "string", "description": "Regex pattern to search for"}, "path": {"type": "string", "description": "Directory or file to search in"}, "file_pattern": {"type": "string", "description": "Glob pattern to filter files"}, "case_sensitive": {"type": "boolean", "default": true}, "max_results": {"type": "integer", "default": 100}, "context_lines": {"type": "integer", "default": 0}}, "required": ["pattern"]}}

{"name": "glob_search", "description": "Find files matching a glob pattern with sorting and filtering.", "parameters": {"type": "object", "properties": {"pattern": {"type": "string", "description": "Glob pattern (e.g., '**/*.py')"}, "path": {"type": "string", "description": "Base directory to search from"}, "sort_by": {"type": "string", "enum": ["name", "modified", "size"]}, "limit": {"type": "integer"}}, "required": ["pattern"]}}

{"name": "git_status", "description": "Get the current git status including staged, unstaged, and untracked files.", "parameters": {"type": "object", "properties": {"path": {"type": "string", "description": "Repository path"}, "short": {"type": "boolean", "default": false}}}}

{"name": "git_diff", "description": "Show git diff for files with configurable options.", "parameters": {"type": "object", "properties": {"path": {"type": "string", "description": "File or directory to diff"}, "staged": {"type": "boolean", "default": false}, "commit": {"type": "string", "description": "Compare against specific commit"}}}}

{"name": "git_log", "description": "Show git commit history with filtering options.", "parameters": {"type": "object", "properties": {"count": {"type": "integer", "default": 10}, "path": {"type": "string"}, "author": {"type": "string"}, "since": {"type": "string"}, "format": {"type": "string", "enum": ["oneline", "short", "medium", "full"]}}}}

{"name": "git_commit", "description": "Create a git commit with the staged changes.", "parameters": {"type": "object", "properties": {"message": {"type": "string", "description": "Commit message"}, "amend": {"type": "boolean", "default": false}}, "required": ["message"]}}

{"name": "web_search", "description": "Search the web for information.", "parameters": {"type": "object", "properties": {"query": {"type": "string", "description": "Search query"}, "num_results": {"type": "integer", "default": 5}}, "required": ["query"]}}

{"name": "web_fetch", "description": "Fetch content from a URL.", "parameters": {"type": "object", "properties": {"url": {"type": "string", "description": "URL to fetch"}, "format": {"type": "string", "enum": ["text", "html", "markdown"]}}, "required": ["url"]}}

